1	export type Cell = [number, number];
2	
3	const key = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [0, -1], [1, -1],
7	  [-1,  0],          [1,  0],
8	  [-1,  1], [0,  1], [1,  1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
15	  const aliveKeys = new Set(liveCells.map(key));
16	  const isAlive = (cell: Cell): boolean => aliveKeys.has(key(cell));
17	  const liveNeighborCount = (cell: Cell): number =>
18	    neighborsOf(cell).filter(isAlive).length;
19	  const willLive = (cell: Cell): boolean => {
20	    const count = liveNeighborCount(cell);
21	    return isAlive(cell) ? count === 2 || count === 3 : count === 3;
22	  };
23	
24	  const candidates = new Map<string, Cell>();
25	  for (const cell of liveCells) {
26	    candidates.set(key(cell), cell);
27	    for (const neighbor of neighborsOf(cell)) {
28	      candidates.set(key(neighbor), neighbor);
29	    }
30	  }
31	  return [...candidates.values()].filter(willLive);
32	};
