1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	const sortCells = (cells: [number, number][]): [number, number][] =>
5	  [...cells].sort(([ax, ay], [bx, by]) => ax - bx || ay - by);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty grid stays empty — [] → []", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("Rule 1 underpopulation: two adjacent cells both die (each has 1 neighbor) — [(0,1), (1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	  it("Rule 2 survival: center cell of vertical blinker with 2 neighbors survives — result contains (0,1)", () => {
18	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
19	    expect(result).toContainEqual([0, 1]);
20	  });
21	  it("Rule 3 overpopulation: center cell with 4 neighbors dies — center (1,1) not in result", () => {
22	    const result = nextGeneration([
23	      [0, 0], [1, 0], [2, 0],
24	      [1, 1],
25	      [0, 2], [1, 2], [2, 2],
26	    ]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("Rule 4 reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape result contains (1,1)", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(result).toContainEqual([1, 1]);
32	  });
33	  it("Block (still life): 2x2 block remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
34	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
35	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
36	  });
37	  it.todo("Blinker (oscillator): vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]");
38	  it.todo("handles negative coordinates — blinker at negative offset oscillates correctly");
39	});
