const uniqueByKey = (cells: Cell[]): Cell[] =>
  [...new Map(cells.map((cell) => [key(cell), cell])).values()];

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const aliveKeys = new Set(liveCells.map(key));
  const isAlive = (cell: Cell): boolean => aliveKeys.has(key(cell));
  const liveNeighborCount = (cell: Cell): number =>
    neighborsOf(cell).filter(isAlive).length;
  const willLive = (cell: Cell): boolean => {
    const count = liveNeighborCount(cell);
    return isAlive(cell) ? count === 2 || count === 3 : count === 3;
  };

  const candidates = uniqueByKey([
    ...liveCells,
    ...liveCells.flatMap(neighborsOf),
  ]);
  return candidates.filter(willLive);
};

